  2	import { Bullseye, Spinner, Text } from '@patternfly/react-core';
  3	import { Visualization, VisualizationProvider } from '@patternfly/react-topology';
  4	import _ from 'lodash';
  5	import * as React from 'react';
  6	import { useTranslation } from 'react-i18next';
  7	import {
  8	  FunctionMetrics,
  9	  getFunctionMetricKey,
 10	  getRateMetricKey,
 11	  RateMetrics,
 12	  Stats,
 13	  TopologyMetrics
 14	} from '../../../api/loki';
 15	import { getK8SUDNIds } from '../../../api/routes';
 16	import { Config } from '../../../model/config';
 17	import { FilterDefinition, Filters } from '../../../model/filters';
 18	import { FlowScope, isTimeMetric, MetricFunction, MetricType, StatFunction } from '../../../model/flow-query';
 19	import { useNetflowContext } from '../../../model/netflow-context';
 20	import { ScopeConfigDef } from '../../../model/scope';
 21	import { GraphElementPeer, LayoutName, TopologyOptions } from '../../../model/topology';
 22	import { TimeRange } from '../../../utils/datetime';
 23	import { getStructuredHTTPError } from '../../../utils/errors';
 24	import { observeDOMRect } from '../../../utils/metrics-helper';
 25	import { Result } from '../../../utils/result';
 26	import { fetchNetworkHealth } from '../../health/health-fetcher';
 27	import { buildStats, HealthStats } from '../../health/health-helper';
 28	import { SearchEvent, SearchHandle } from '../../search/search';
 29	import { ScopeSlider } from '../../slider/scope-slider';
 30	import componentFactory from './2d/componentFactories/componentFactory';
 31	import stylesComponentFactory from './2d/componentFactories/stylesComponentFactory';
 32	import layoutFactory from './2d/layouts/layoutFactory';
 33	import { TopologyContent } from './2d/topology-content';
 34	import './netflow-topology.css';
 35	
 36	export type NetflowTopologyHandle = {
 37	  fetch: (
 38	    metricType: MetricType,
 39	    metricFunction: StatFunction,
 40	    range: number | TimeRange
 41	  ) => Promise<Stats[]> | undefined;
 42	  fetchUDNs: () => Promise<string[]>;
 43	};
 44	
 45	export interface NetflowTopologyProps {
 46	  loading?: boolean;
 47	  k8sModels: { [key: string]: K8sModel };
 48	  metricFunction: StatFunction;
 49	  metricType: MetricType;
 50	  metricScope: FlowScope;
 51	  expectedNodes: string[];
 52	  setMetricScope: (ms: FlowScope) => void;
 53	  metrics: TopologyMetrics[];
 54	  droppedMetrics: TopologyMetrics[];
 55	  options: TopologyOptions;
 56	  setOptions: (o: TopologyOptions) => void;
 57	  filters: Filters;
 58	  filterDefinitions: FilterDefinition[];
 59	  setFilters: (v: Filters) => void;
 60	  selected: GraphElementPeer | undefined;
 61	  onSelect: (e: GraphElementPeer | undefined) => void;
 62	  searchHandle: SearchHandle | null;
 63	  searchEvent?: SearchEvent;
 64	  isDark?: boolean;
 65	  scopes: ScopeConfigDef[];
 66	  resetDefaultFilters?: (c?: Config) => void;
 67	  clearFilters?: () => void;
 68	}
 69	
 70	// eslint-disable-next-line react/display-name
 71	export const NetflowTopology = React.forwardRef<NetflowTopologyHandle, NetflowTopologyProps>((props, ref) => {
 72	  const { t } = useTranslation('plugin__netobserv-plugin');
 73	  const { caps, config, fetchCallbacks } = useNetflowContext();
 74	
 75	  const containerRef = React.useRef<HTMLDivElement>(null);
 76	  const [containerSize, setContainerSize] = React.useState<DOMRect>({ width: 0, height: 0 } as DOMRect);
 77	  const [controller, setController] = React.useState<Visualization>();
 78	  const [health, setHealth] = React.useState<HealthStats>(buildStats([]));
 79	  const [lastStatsUpdateTime, setLastStatsUpdateTime] = React.useState<number>(0);
 80	  const statsRefreshIntervalMs = 30000; // Refresh stats every 30 seconds if outdated
 81	
 82	  // Memoize health to prevent unnecessary getContent re-creation
 83	  const memoizedHealth = React.useMemo(() => health, [health]);
 84	
 85	  //show fully dropped metrics if no metrics available
 86	  const displayedMetrics = React.useMemo(
 87	    () => (_.isEmpty(props.metrics) ? props.droppedMetrics : props.metrics),
 88	    [props.metrics, props.droppedMetrics]
 89	  );
 90	
 91	  const fetchHealth = React.useCallback(async () => {
 92	    try {
 93	      // matching netobserv="true" catches all alerts designed for netobserv (not necessarily owned by it)
 94	      const res = await fetchNetworkHealth(config.recordingAnnotations || {});
 95	      setHealth(res.stats);
 96	      setLastStatsUpdateTime(Date.now());
 97	    } catch (err) {
 98	      console.log('Could not fetch topology alerts:', err);
 99	    }
100	  }, [config.recordingAnnotations]);
101	
102	  // Trigger stats refresh if outdated
103	  const refreshResourceStatsIfNeeded = React.useCallback(() => {
104	    const now = Date.now();
105	    if (now - lastStatsUpdateTime > statsRefreshIntervalMs) {
106	      fetchHealth();
107	    }
108	  }, [lastStatsUpdateTime, statsRefreshIntervalMs, fetchHealth]);
109	
110	  const fetch = React.useCallback(
111	    (metricType: MetricType, metricFunction: StatFunction, range: number | TimeRange) => {
112	      const fq = caps.flowQuery;
113	      const features = config.features;
114	      const { getMetrics } = caps.fetchFunctions;
115	      const { metricsRef, setFlows, setMetrics, setError } = fetchCallbacks;
116	
117	      setFlows([]);
118	
119	      // Refresh resource stats if outdated
120	      refreshResourceStatsIfNeeded();
121	
122	      const droppedType = features.includes('pktDrop')
123	        ? fq.type === 'Bytes'
124	          ? 'PktDropBytes'
125	          : fq.type === 'Packets'
126	          ? 'PktDropPackets'
127	          : undefined
128	        : undefined;
129	      let currentMetrics = { ...metricsRef.current };
130	
131	      const promises: Promise<Stats>[] = [
132	        getMetrics(
133	          {
134	            ...fq,
135	            function: isTimeMetric(metricType) ? (metricFunction as MetricFunction) : 'rate'
136	          },
137	          range
138	        ).then(res => {
139	          if (['Bytes', 'Packets'].includes(metricType)) {
140	            const rateMetrics = {} as RateMetrics;
141	            rateMetrics[getRateMetricKey(metricType)] = res.metrics;
142	            currentMetrics = {
143	              ...currentMetrics,
144	              rate: Result.success(rateMetrics),
145	              dnsLatency: Result.empty(),
146	              rtt: Result.empty()
147	            };
148	            setMetrics(currentMetrics);
149	          } else if (['PktDropBytes', 'PktDropPackets'].includes(metricType)) {
150	            const droppedRateMetrics = {} as RateMetrics;
151	            droppedRateMetrics[getRateMetricKey(metricType)] = res.metrics;
152	            currentMetrics = { ...currentMetrics, droppedRate: Result.success(droppedRateMetrics) };
153	            setMetrics(currentMetrics);
154	          } else if (['DnsLatencyMs'].includes(metricType)) {
155	            const dnsLatencyMetrics = {} as FunctionMetrics;
156	            dnsLatencyMetrics[getFunctionMetricKey(metricFunction)] = res.metrics;
157	            currentMetrics = {
158	              ...currentMetrics,
159	              rate: Result.empty(),
160	              dnsLatency: Result.success(dnsLatencyMetrics),
161	              rtt: Result.empty()
162	            };
163	            setMetrics(currentMetrics);
164	          } else if (['TimeFlowRttNs'].includes(metricType)) {
165	            const rttMetrics = {} as FunctionMetrics;
166	            rttMetrics[getFunctionMetricKey(metricFunction)] = res.metrics;
167	            currentMetrics = {
168	              ...currentMetrics,
169	              rate: Result.empty(),
170	              dnsLatency: Result.empty(),
171	              rtt: Result.success(rttMetrics)
172	            };
173	            setMetrics(currentMetrics);
174	          }
175	          return res.stats;
176	        })
177	      ];
178	
179	      if (droppedType) {
180	        promises.push(
181	          getMetrics({ ...fq, type: droppedType }, range)
182	            .then(res => {
183	              const droppedRateMetrics = {} as RateMetrics;
184	              droppedRateMetrics[getRateMetricKey(metricType)] = res.metrics;
185	              currentMetrics = { ...currentMetrics, droppedRate: Result.success(droppedRateMetrics) };
186	              setMetrics(currentMetrics);
187	              return res.stats;
188	            })
189	            .catch(err => {
190	              // Error might occur for instance when fetching node-based topology with drop feature enabled, and Loki disabled
191	              // We don't want to break the whole topology due to missing drops enrichement
192	              const pErr = getStructuredHTTPError(err);
193	              setError(pErr);
194	              return { numQueries: 0, dataSources: [], limitReached: false };
195	            })
196	        );
197	      } else if (!['PktDropBytes', 'PktDropPackets'].includes(metricType)) {
198	        currentMetrics = { ...currentMetrics, droppedRate: Result.empty() };
199	        setMetrics(currentMetrics);
200	      }
201	      return Promise.all(promises);
202	    },
203	    [refreshResourceStatsIfNeeded, caps.flowQuery, caps.fetchFunctions, config.features, fetchCallbacks]
204	  );
205	
206	  // Initial fetch and setup update trigger
207	  React.useEffect(() => {
208	    fetchHealth();
209	  }, [fetchHealth]);
210	
211	  const fetchUDNs = React.useCallback(() => {
212	    // Refresh resource stats if outdated
213	    refreshResourceStatsIfNeeded();
214	    return getK8SUDNIds();
215	  }, [refreshResourceStatsIfNeeded]);
216	
217	  React.useImperativeHandle(ref, () => ({
218	    fetch,
219	    fetchUDNs
220	  }));
221	
222	  const getContent = React.useCallback(() => {
223	    if (props.options.layout === LayoutName.threeD) {
224	      return <Text component="p">{t('Sorry, 3D view is not implemented anymore.')}</Text>;
225	    }
226	
227	    // Always render TopologyContent once controller is ready
228	    // Show loading overlay instead of unmounting
229	    if (!controller) {
230	      return (
231	        <Bullseye data-test="loading-contents">
232	          <Spinner size="xl" />
233	        </Bullseye>
234	      );
235	    }
236	
237	    const showLoadingOverlay = _.isEmpty(props.metrics) && props.loading;
238	
239	    return (
240	      <div style={{ position: 'relative', width: '100%', height: '100%' }}>
241	        {showLoadingOverlay && (
242	          <Bullseye
243	            data-test="loading-contents"
244	            style={{
245	              position: 'absolute',
246	              top: 0,
247	              left: 0,
248	              right: 0,
249	              bottom: 0,
250	              backgroundColor: props.isDark ? '#151515' : '#ffffff',
251	              zIndex: 1000
252	            }}
253	          >
254	            <Spinner size="xl" />
255	          </Bullseye>
256	        )}
257	        <VisualizationProvider data-test="visualization-provider" controller={controller}>
258	          <TopologyContent
259	            containerRef={containerRef}
260	            k8sModels={props.k8sModels}
261	            expectedNodes={props.expectedNodes}
262	            metricFunction={props.metricFunction}
263	            metricType={props.metricType}
264	            metricScope={props.metricScope}
265	            setMetricScope={props.setMetricScope}
266	            scopes={props.scopes}
267	            metrics={displayedMetrics}
268	            droppedMetrics={props.droppedMetrics}
269	            options={props.options}
270	            filters={props.filters}
271	            filterDefinitions={props.filterDefinitions}
272	            setFilters={props.setFilters}
273	            selected={props.selected}
274	            onSelect={props.onSelect}
275	            searchHandle={props.searchHandle}
276	            searchEvent={props.searchEvent}
277	            isDark={props.isDark}
278	            resetDefaultFilters={props.resetDefaultFilters}
279	            clearFilters={props.clearFilters}
280	            resourceStats={memoizedHealth}
281	          />
282	        </VisualizationProvider>
283	      </div>
284	    );
285	    // eslint-disable-next-line react-hooks/exhaustive-deps
286	  }, [controller, props, displayedMetrics]);
287	
288	  //create controller on startup and register factories
289	  React.useEffect(() => {
290	    const c = new Visualization();
291	    c.registerLayoutFactory(layoutFactory);
292	    c.registerComponentFactory(componentFactory);
293	    c.registerComponentFactory(stylesComponentFactory);
294	    setController(c);
295	    // eslint-disable-next-line react-hooks/exhaustive-deps
296	  }, []);
297	
298	  React.useEffect(() => {
299	    return observeDOMRect(containerRef, containerSize, setContainerSize);
300	  }, [containerRef, containerSize, setContainerSize]);
301	
302	  return (
303	    <div id="topology-container-div" style={{ width: '100%', height: '100%' }} ref={containerRef}>
304	      <div id={'topology-scope-slider-div'}>
305	        <ScopeSlider scope={props.metricScope} setScope={props.setMetricScope} scopeDefs={props.scopes} />
306	      </div>
307	      <div id="topology-view-div">{getContent()}</div>
308	    </div>
309	  );
310	});
311	
312	export default NetflowTopology;

